sql:
SELECT name
FROM whiskies
WHERE super_cluster_id = 0;

SELECT AVG(meta_critic_score) AS average_score
  FROM whiskies
  WHERE country_id = 1;

SELECT AVG(meta_critic_score) AS average_score
FROM whiskies
WHERE country_id = 1;

SELECT name, num_reviews AS review_count
FROM whiskies
ORDER BY num_reviews DESC;

SELECT name
FROM whiskies
WHERE meta_critic_score = (SELECT MAX(meta_critic_score) FROM whiskies);

external_knowledge:
- 'exquisite whiskies' refers to whiskies with an average rating of 4.0 or higher;
- 'a wealth of opinions' refers to whiskies with at least 50 ratings;
- 'a hefty price tag' refers to whiskies with a minimum price between $50 and $200;
- 'a rating to die for' refers to the highest average rating in the filtered list.
